    <h1>Corrected Fibonacci Spiral</h1>
    <canvas id="corrected-canvas" width="400" height="400"></canvas>

    <script>
        // Function to generate Fibonacci sequence
        function* fibonacci() {
            let a = 0;
            let b = 1;
            yield a;
            yield b;
            while (true) {
                [a, b] = [b, a + b];
                yield b;
            }
        }

        // Draw Fibonacci spiral on canvas
        function drawFibonacciSpiral(ctx, canvasWidth, canvasHeight, maxFib) {
            ctx.clearRect(0, 0, canvasWidth, canvasHeight);
            ctx.beginPath();
            ctx.translate(canvasWidth / 2, canvasHeight / 2);
            ctx.strokeStyle = 'black';

            const fibGen = fibonacci();
            let prevAngle = 0;
            let radius = 0;

            for (let i = 0; i < maxFib; i++) {
                const fibNum = fibGen.next().value;
                radius += fibNum;

                ctx.arc(0, 0, radius, prevAngle, prevAngle + Math.PI / 2);
                prevAngle += Math.PI / 2;
            }

            ctx.stroke();
        }

        // Get canvases and contexts
        const buggyCanvas = document.getElementById('buggy-canvas');
        const buggyCtx = buggyCanvas.getContext('2d');
        const correctedCanvas = document.getElementById('corrected-canvas');
        const correctedCtx = correctedCanvas.getContext('2d');

