        buggyCtx.beginPath();
        buggyCtx.translate(buggyCanvas.width / 2, buggyCanvas.height / 2);
        buggyCtx.strokeStyle = 'red';
        const buggyFibGen = fibonacci();
        buggyFibGen.next(); // Skip first 0
        buggyFibGen.next(); // Skip 1, but actually use 1 as radius
        let buggyRadius = 10; // Incorrect base case
        buggyCtx.moveTo(buggyRadius, 0);
        for (let i = 0; i < 10; i++) {
            const fibNum = buggyFibGen.next().value;
            buggyRadius += fibNum;
            buggyCtx.lineTo(buggyRadius, 0);
            buggyCtx.rotate(Math.PI / 2);
